sys_script_include.script:
var TaniumDeployUtil = Class.create();
TaniumDeployUtil.prototype = Object.extendsObject(x_taniu_tan_core.TaniumIntegrationCore, {

	//Replaced with this._initDeployConfigIfEmpty():
	/*_config : {
		'description' : 'Deployment from ServiceNow',
		'spkg_id' : 0,
		'endpoints' : [],
		'operation' : 'INSTALL_OR_UPDATE',
		'start' : {},
		'end' : {},
		'last_deployment_id' : 0
	},*/


	/**
	 * Trigger the deployment which has been configured by calling methods such as
	 * .addEndpointBySerial().
	 * @returns {{data}|Object} Returns the response object from Tanium, including the ID
	 *  which can be found at .deploy().data.manageSoftware.ID.
	 */
	deploy : function () {
		this._initDeployConfigIfEmpty();
		var iEndpoint, responseBody, rDeployment;

		if (!this._validateConfig()) {
			//Config is invalid; halt and return false. Validation method already logged errors.
			throw new Error(
				'Attempted deploy using TaniumDeployUtil, but config was not valid. Please ' +
				'see documentation and perform necessary setup such as calling ' +
				'.addEndpointByID() to set up the deploy call.'
			);
		}

		rDeployment = this._getRESTObject(
			'Tanium Integration Core',
			'Deploy-Create Deployment'
		);

		rDeployment.setStringParameterNoEscape('tanium_module_api_url', this.TANIUM_MODULE_API_ENDPOINT);

		//Deployment info
		rDeployment.setStringParameterNoEscape('spkg_id', this._config.spkg_id);
		rDeployment.setStringParameterNoEscape('endpoint_ids', this._config.endpoints.join(', '));
		rDeployment.setStringParameterNoEscape('deploy_description', '');
		rDeployment.setStringParameterNoEscape('deploy_operation', this._config.operation);

		//Start date
		rDeployment.setStringParameterNoEscape('start_year', this._config.start.year);
		rDeployment.setStringParameterNoEscape('start_month', this._config.start.month);
		rDeployment.setStringParameterNoEscape('start_day', this._config.start.day);
		//Start time
		rDeployment.setStringParameterNoEscape('start_hour', this._config.start.hour);
		rDeployment.setStringParameterNoEscape('start_min', this._config.start.minute);
		rDeployment.setStringParameterNoEscape('start_sec', this._config.start.second);

		//End date
		rDeployment.setStringParameterNoEscape('end_year', this._config.end.year);
		rDeployment.setStringParameterNoEscape('end_month', this._config.end.month);
		rDeployment.setStringParameterNoEscape('end_day', this._config.end.day);
		//End time
		rDeployment.setStringParameterNoEscape('end_hour', this._config.end.hour);
		rDeployment.setStringParameterNoEscape('end_min', this._config.end.minute);
		rDeployment.setStringParameterNoEscape('end_sec', this._config.end.second);

		responseBody = this._executeRESTCall(
			rDeployment,
			false,
			true,
			false
		);

		if (
			!responseBody.hasOwnProperty('data') ||
			!responseBody.data.hasOwnProperty('manageSoftware') ||
			!responseBody.data.manageSoftware.hasOwnProperty('ID')
		) {
			throw new Error(
				'TaniumDeployUtil received invalid Deploy response body: \n' +
				JSON.stringify(responseBody, null, 2) + '\n' +
				'Halting execution.'
			);
		}

		this._config.last_deployment_id = parseInt(responseBody.data.manageSoftware.ID);

		for (iEndpoint = 0; iEndpoint < this._config.endpoints.length; iEndpoint++) {
			this._logAction(
				'',
				this._config.endpoints[iEndpoint],
				'Deploy-Create Deployment',
				('Create deployment of Tanium "Deploy" Software Package with package ID ' +
					this._config.spkg_id + ' on endpoint with endpoint ID ' +
					this._config.endpoints[iEndpoint] + '.'),
				(this._config.last_deployment_id ? this._config.last_deployment_id.toFixed(0) : '')
			);
		}

		return responseBody;
	},

	/**
	 * Set the package ID for the package to be deployed using this instantiation
	 *  of the TaniumDeployUtil Script Include.
	 * This is a necessary step before deploying a package using TaniumDeployUtil.
	 * @param {Number} spkgID - The Tanium Deploy Package ID. You can find the
	 *  Package ID in Tanium by navigating to the Deploy Module, then to the
	 *  Package Gallery in Tanium.
	 * @returns {this}
	 */
	setPackageID : function (spkgID) {
		this._initDeployConfigIfEmpty();
		spkgID = parseInt(spkgID);
		if (!spkgID) {
			throw new Error(
				'Invalid Tanium Deploy software package ID specified. Unable to set package ID.'
			);
		}

		this._config.spkg_id = spkgID;

		return this;
	},

	/**
	 * Set the serial number of the endpoint on which to trigger the deployment using Tanium
	 *  Deploy. Can be called multiple times to add multiple endpoints.
	 * @param {String} endpointSerialNumber - The serial number of the endpoint on
	 *  which to trigger the deployment using Tanium Deploy.
	 * @returns {this}
	 */
	addEndpointBySerial : function (endpointSerialNumber) {
		var endpointID = this.getEndpointIDBySerial(endpointSerialNumber);

		if (!endpointSerialNumber || !endpointID) {
			throw new Error(
				'Error adding endpoint to deployment using Tanium Deploy. A valid serial ' +
				'number was not specified. This may happen if the endpoint is not managed ' +
				'by Tanium.\n' +
				'Provided serial number: "' + endpointSerialNumber + '".'
			);
		}

		return this.addEndpointByID(endpointID);
	},

	/**
	 * Set the endpoint ID of the endpoint on which to trigger the deployment using
	 *  Tanium Deploy. Can be called multiple times to trigger the deployment on
	 *  multiple endpoints.
	 * The endpoint ID can be obtained by calling .getEndpointIDBySerial() since
	 *  TaniumDeployUtil extends TaniumIntegrationCore.
	 * @param {Number} endpointID - The Endpoint ID for an endpoint within Tanium, as an integer.
	 * @returns {this}
	 */
	addEndpointByID : function (endpointID) {
		this._initDeployConfigIfEmpty();
		endpointID = parseInt(endpointID);

		if (!endpointID) {
			throw new Error(
				'Invalid Tanium Endpoint ID "' + endpointID + '" specified. ' +
				'Unable to add Endpoint for deployment using Tanium Deploy.'
			);
		}
		if (this._config.endpoints.indexOf(endpointID) >= 0) {
			gs.warn(
				'Endpoint ID "' + endpointID + '" already added to deployment. Skipping.\n' +
				'Endpoint IDs for current deployment: \n' +
				JSON.stringify(this._config.endpoints, null, 2)
			);
			return this;
		}
		if (this._config.endpoints.length >= 25) {
			throw new Error(
				'New endpoint added, but maximum endpoints (25) already specified. ' +
				'Only 25 endpoints can be added per Tanium Deployment.'
			);
		}

		//Add the endpoint to the endpoint list
		this._config.endpoints.push(endpointID);

		return this;
	},

	/**
	 * Set the description for the deployment using Tanium Deploy.
	 * @param {String} newDescription - The description for the deployment using Tanium Deploy.
	 * @returns {this}
	 */
	setDescription : function (newDescription) {
		this._initDeployConfigIfEmpty();
		if (newDescription) {
			this._config.description = newDescription;
		} else {
			gs.warn(
				'Invalid or empty description passed to ' +
				'TaniumDeployUtil.setDescription(). Ignoring.'
			);
		}

		return this;
	},

	/**
	 * Set the Tanium Deploy operation for this deployment.
	 * @param {'INSTALL'|'INSTALL_OR_UPDATE'|'REMOVE'|'UPDATE'} operation - The Tanium Deploy
	 *  operation to be performed by this deployment. Must be one of the enumerated values
	 *  ('INSTALL', 'INSTALL_OR_UPDATE', 'REMOVE', 'UPDATE').
	 * @returns {this} - Returns `this` for chain-calling.
	 */
	setOperation : function (operation) {
		this._initDeployConfigIfEmpty();
		var validOperations = ['INSTALL', 'INSTALL_OR_UPDATE', 'REMOVE', 'UPDATE'];
		operation = operation.toUpperCase();

		if (!operation || validOperations.indexOf(operation) < 0) {
			throw new Error(
				'Invalid Tanium Deploy operation "' + operation + '" specified. \n' +
				'Operation must be one of the following valid Deploy operations:\n' +
				validOperations.join('\n')
			);
		}

		this._config.operation = operation;
		return this;
	},

	/**
	 * Set the number of hours after which the deployment will stop.
	 * @param {Number} [deployDurationHrs=gs.getProperty('x_taniu_tan_core.default_deployment_duration_hrs') -
	 *     The number of hours after which the deployment will stop (0 to 1000).
	 * @returns {this}
	 */
	setDeployDurationHrs : function (deployDurationHrs) {
		this._initDeployConfigIfEmpty();
		var deployTimeValues;
		deployDurationHrs = parseInt(deployDurationHrs);

		if (!deployDurationHrs) {
			gs.warn(
				'Invalid deploy duration "' + deployDurationHrs + '" specified; ' +
				'unable to set Tanium Deploy duration, so using default duration instead.'
			);
		}

		deployTimeValues = this._getDeploymentTimeValues(deployDurationHrs);

		this._config.start = deployTimeValues.start;
		this._config.end = deployTimeValues.end;

		return this;
	},

	/**
	 * Get the status of an existing deployment, by deployment ID (returned from
	 *  .deploy().data.manageSoftware.ID).
	 * If this method is called immediately after calling .deploy() then no meaningful result
	 *  will be returned, since the deployment has not yet had a chance to do anything.
	 * Be careful to put checks in when calling this method in a loop, to prevent an
	 *  accidental infinite loop if deployment expires or never completes.
	 * @param {number} [deploymentID=this._config.last_deployment_id] - The deployment ID for
	 *  which to get the status.
	 * @returns {{failedCount: number, downloadCompleteWaitingCount: number, notApplicableCount:
	 *     number, runningCount: number, label: string, downloadingCount: number, completeCount:
	 *     number, waitingCount: number}} Returns an object indicating the counts for each possible
	 *     status
	 */
	getDeploymentStatus : function (deploymentID) {
		this._initDeployConfigIfEmpty();
		var responseBody, rDeployStatus;

		deploymentID = deploymentID || this._config.last_deployment_id;

		if (!deploymentID) {
			throw new Error(
				'Invalid deployment ID specified. Unable to get deployment status from Tanium.'
			);
		}

		rDeployStatus = this._getRESTObject(
			'Tanium Integration Core',
			'Deploy-Get Deployment Status'
		);

		rDeployStatus.setStringParameterNoEscape('tanium_module_api_url', this.TANIUM_MODULE_API_ENDPOINT);
		rDeployStatus.setStringParameterNoEscape('deployment_id', deploymentID);

		responseBody = this._executeRESTCall(
			rDeployStatus,
			false,
			true,
			false
		);

		if (
			!responseBody.hasOwnProperty('data') ||
			!responseBody.data.hasOwnProperty('softwareDeployment') ||
			!responseBody.data.softwareDeployment.length > 0 ||
			!responseBody.data.softwareDeployment[0].hasOwnProperty('status')
		) {
			throw new Error(
				'TaniumDeployUtil received invalid Deployment status response body: \n' +
				JSON.stringify(responseBody, null, 2) + '\n' +
				'Halting.'
			);
		}

		return responseBody.data.softwareDeployment[0].status;
	},

	/**
	 * Get an object from the Tanium Deploy API that contains information about all Packages
	 *  within Tanium Deploy.
	 * @param {boolean} [excludeInProgress=true] - To include packages that are currently being
	 *  newly edited and have not yet been published, set this argument to false. Otherwise,
	 *  set it to true or don't specify it, and only published packages will be included.
	 * @returns {[]} - An array of Tanium Deploy Package objects, and all associated
	 *  information about them.
	 */
	getDeploySoftwarePackages : function (excludeInProgress) {
		excludeInProgress = (typeof excludeInProgress !== 'boolean') ? true : excludeInProgress;

		return this._getDeployPackages(excludeInProgress);
	},

	/**
	 * Get the GlideRecord corresponding to the Tanium Deploy Package with the specified package
	 *  ID, from the Deploy Software Package [x_taniu_tan_core_deploy_spkg] table.
	 * @param deployPkgID
	 * @private
	 */
	getDeployPackageByID : function (deployPkgID) {
		var pkgTableName = this.deploy_package_table_name;
		var grDeployPkg;

		if (typeof deployPkgID == 'undefined') {
			throw new Error(
				'deployPkgID parameter not specified when calling getDeployPackageByID. ' +
				'Cannot continue without a package ID.'
			);
		}

		grDeployPkg = new GlideRecord(pkgTableName);
		grDeployPkg.addQuery('package_id', deployPkgID);
		grDeployPkg.setLimit(1);
		grDeployPkg.query();
		if (grDeployPkg.next()) {
			return grDeployPkg;
		}

		//Return false if not found
		return false;
	},

	/**
	 * upcoming_feature
	 * @param productVendor
	 * @param excludeInProgress
	 * @returns {boolean|*}
	 * @private
	 * @example
	 * var tdu = new TaniumDeployUtil();
	 * gs.info(
	 * 	//gs.urlEncode('this is a test')
	 * 	JSON.stringify(
	 * 		tdu.getDeployPackagesByVendor('Adobe'), null, 2
	 * 	)
	 * );
	 */
	_getDeployPackagesByVendor : function (productVendor, excludeInProgress) {
		excludeInProgress = (typeof excludeInProgress !== 'boolean') ? true : excludeInProgress;

		return this._getDeployPackages(excludeInProgress, productVendor);
	},

	/**
	 * upcoming_feature
	 * @param {String} productName - The EXACT name of the product to get the Deploy package for.
	 * Partial string matching is not supported. This value is case-sensitive. For example, if
	 *  you're looking for Firefox, this value must be "Firefox"; not "firefox" or "Firefox (x64)".
	 * @param {Boolean} [excludeInProgress=true] - To get packages that are currently
	 *  "in progress" in Tanium Deploy, set this to false.
	 * Default value: true
	 * @returns {boolean|*} - An object containing details about all Tanium Deploy packages.
	 * Returns false if there was an error getting package details.
	 * @example
	 * var tdu = new TaniumDeployUtil();
	 * gs.info(
	 * 	JSON.stringify(tdu.getDeploySoftwarePackages(), null, 2)
	 * );
	 */
	_getDeployPackagesByName : function (productName, excludeInProgress) {
		excludeInProgress = (typeof excludeInProgress !== 'boolean') ? true : excludeInProgress;

		return this._getDeployPackages(excludeInProgress, null, productName);
	},

	/**
	 * upcoming_feature
	 * @param platform
	 * @param productName
	 * @param productVendor
	 * @param excludeInProgress
	 * @returns {*[]}
	 */
	_getDeployPackagesByPlatform : function (platform, productName, productVendor, excludeInProgress) {
		var i, deployPackages;
		var platformPackages = [];
		var validPlatforms = ['windows', 'macos', 'linux'];
		excludeInProgress = (typeof excludeInProgress !== 'boolean') ? true : excludeInProgress;
		platform = platform.toLowerCase();

		if (validPlatforms.indexOf(platform) < 0) {
			throw new Error(
				'Invalid platform, "' + platform + '", specified. Valid platform rows: \n' +
				validPlatforms.join(', ')
			);
		}

		deployPackages = this._getDeployPackages(
			excludeInProgress,
			productVendor,
			productName
		);

		for (i = 0; i < deployPackages.length; i++) {
			if (deployPackages[i].platform == platform) {
				platformPackages.push(deployPackages[i]);
			}
		}

		return platformPackages;
	},


	/*** HELPER METHODS BELOW ***/

	_getDeployPackages : function (excludeInProgress, productVendor, productName) {
		var responseBody, rGetDeployPackages;
		//Default value: true
		excludeInProgress = (typeof excludeInProgress !== 'boolean') ? true : excludeInProgress;

		rGetDeployPackages = this._getRESTObject(
			'Tanium Integration Core',
			'Deploy-Get Deploy Software Packages'
		);

		rGetDeployPackages.setStringParameterNoEscape('tanium_module_api_url', this.TANIUM_MODULE_API_ENDPOINT);
		rGetDeployPackages.setStringParameterNoEscape('exclude_in_progress', excludeInProgress);

		/*
			If product name is specified, filter by product name.
			If product name is not specified, then check if product vendor is specified. If so,
			 filter by vendor instead.
			Note that according to this pattern, if product name and vendor are both specified,
			 only product name is used to filter. This is because that's the behavior of this API.
			 The queries are not combined; so only the more specific one (product name) is used.
		 */
		if (productName) {
			rGetDeployPackages.setStringParameterNoEscape(
				'product_name',
				gs.urlEncode(productName)
			);
		} else if (productVendor) {
			rGetDeployPackages.setStringParameterNoEscape(
				'product_vendor',
				gs.urlEncode(productVendor)
			);
		}

		responseBody = this._executeRESTCall(
			rGetDeployPackages,
			false,
			true,
			false,
			//Override default async behavior for this call, since the response is probably very large.
			// This is a private method, and we know what we're doing.
			true
		);

		if (!responseBody.hasOwnProperty('data')) {
			gs.error(
				'TaniumDeployUtil received invalid response body when querying software packages: \n' +
				JSON.stringify(responseBody, null, 2) + '\n' +
				'Halting.'
			);
			return false; //Halt if error
		}

		return responseBody.data;
	},

	_getDeploymentTimeValues : function (hrDeployDuration) {
		var msDeployDuration;
		var gdtStart = new GlideDateTime(); //Now
		var gdtEnd = new GlideDateTime();
		var timeValues = {
			'start' : {},
			'end' : {}
		};

		//Set default value for deployment duration, if not specified.
		if (typeof hrDeployDuration != 'number') {
			hrDeployDuration = parseInt(hrDeployDuration);
		}
		if ((!hrDeployDuration) || (hrDeployDuration < 0) || (hrDeployDuration > 1000)) {
			hrDeployDuration = parseInt(
				gs.getProperty(
					'x_taniu_tan_core.default_deployment_duration_hrs',
					'24'
				)
			);
		}

		//Make sure we got a valid number for deployment duration in hours
		if (!hrDeployDuration || typeof hrDeployDuration != 'number') {
			throw new Error('Unable to parse deployment duration.');
		}

		//Add the deployment duration in ms to the current date/time to get the end date/time.
		msDeployDuration = (
			(
				(
					hrDeployDuration * 60 /*mins*/
				) * 60 /*secs*/
			) * 1000 /*ms*/
		);
		gdtEnd.add(msDeployDuration);

		//Populate object start and end time (updates objects in-place)
		this._populateObjectDateTimeValuesFromGDT(timeValues.start, gdtStart);
		this._populateObjectDateTimeValuesFromGDT(timeValues.end, gdtEnd);

		return timeValues;
	},

	_populateObjectDateTimeValuesFromGDT : function (objectToPopulate, gdt) {
		var gDate = gdt.getDate();
		var gTime = gdt.getTime();

		objectToPopulate.year = gDate.getByFormat('yyyy');
		objectToPopulate.month = gDate.getByFormat('MM');
		objectToPopulate.day = gDate.getByFormat('dd');

		objectToPopulate.hour = gTime.getByFormat('HH'); //24-hour format
		objectToPopulate.minute = gTime.getByFormat('mm');
		objectToPopulate.second = gTime.getByFormat('ss');

		return objectToPopulate;
	},

	_validateConfig : function () {
		this._initDeployConfigIfEmpty();
		var deployDurationHrs;
		var isValid = true;

		if (
			Object.keys(this._config.start).length <= 0 ||
			Object.keys(this._config.end).length <= 0
		) {
			gs.debug(
				'TaniumDeployUtil configuration warning: Config start or end ' +
				'times are not specified. Please call .setDeployDurationHrs() to set the ' +
				'Deploy Duration manually (optional).\n' +
				'Since deploy duration is not specified, using default deploy duration instead.'
			);
			deployDurationHrs = parseInt(
				gs.getProperty(
					'x_taniu_tan_core.default_deployment_duration_hrs',
					'24'
				)
			);
			this.setDeployDurationHrs(deployDurationHrs);
		}

		if (!this._config.operation) {
			isValid = false;
			gs.error(
				'Failed validating TaniumDeployUtil configuration. Operation not set. ' +
				'Please call .setOperation() to set the Tanium Deploy operation to one ' +
				'of the enumerated rows. Default is "INSTALL_OR_UPDATE".'
			);
		}

		if (this._config.endpoints.length <= 0) {
			isValid = false;
			gs.error(
				'Failed validating TaniumDeployUtil endpoints. No endpoints specified for ' +
				'deployment with Tanium Deploy. Please call .addEndpointByID() or ' +
				'.addEndpointBySerial() to add a target endpoint for the deployment.'
			);
		}

		if (!this._config.spkg_id) {
			isValid = false;
			gs.error(
				'Failed validating TaniumDeployUtil software package ID. Invalid or empty ' +
				'package ID specified, or package ID not specified. Please call ' +
				'.setPackageID() to specify the ID of the Tanium Deploy Software Package ' +
				'you\'d like to deploy.'
			);
		}

		return isValid;
	},


	/*************
	 * DEPLOY SPKG SYNC HELPER FUNCTIONS
	 *************/

	/**
	 * Trigger a sync of all existing software packages in Tanium, into the
	 * "x_taniu_tan_core_deploy_spkg" table in ServiceNow.
	 * @example
		var deployUtil = new TaniumDeployUtil();
		deployUtil.syncSoftwarePackages();
	 */
	syncSoftwarePackages : function () {
		var createdPackagesCount, arrSoftwarePackages, arrSpkgIDs;

		arrSoftwarePackages = this.getDeploySoftwarePackages();

		//This must come BEFORE this._updateFoundSoftwarePackages() because that method removes
		// elements from the software packages array as it updates them.
		arrSpkgIDs = this._getAllSpkgIDsFromResponse(arrSoftwarePackages);

		arrSoftwarePackages = this._updateFoundSoftwarePackages(arrSoftwarePackages);
		createdPackagesCount = this._createMissingSoftwarePackages(arrSoftwarePackages);

		//Delete old software packages not found in this sync
		this._deleteOldSoftwarePackages(arrSpkgIDs);


		gs.debug('Created ' + createdPackagesCount + ' new software package records.');
	},

	_getResultStatusForDeployment : function (deployStatusObj) {
		var statusObj = deployStatusObj.status;

		if (statusObj.completeCount > 0) {
			return 'complete';
		}
		if (
			statusObj.downloadCompleteWaitingCount > 0 ||
			statusObj.downloadingCount > 0 ||
			statusObj.runningCount > 0
		) {
			return 'running';
		}
		if (statusObj.waitingCount > 0) {
			return 'waiting';
		}
		if (statusObj.notApplicableCount > 0) {
			return 'not_applicable';
		}
		if (statusObj.failedCount > 0) {
			return 'failed';
		}

		//If none of the above conditions have fired, then check if the deployment is still active.
		//If it is, return status 'other'. If not, return status 'failed'.
		if (statusObj.label == 'ACTIVE') {
			return 'other';
		}

		return 'failed';
	},

	_deleteOldSoftwarePackages : function (spkgIDs) {
		var grSoftwarePackage = new GlideRecord('x_taniu_tan_core_deploy_spkg');
		grSoftwarePackage.addQuery('package_id', 'NOT IN', spkgIDs.join(','));
		gs.debug(
			'Found the following software package IDs in the last sync: \n' +
			JSON.stringify(spkgIDs, null, 2) + '\n' +
			'Deleting all software packages that were NOT found in the last sync.'
		);

		//DELETES ALL SOFTWARE PACKAGES NOT FOUND IN THE LAST SYNC
		grSoftwarePackage.deleteMultiple();
	},

	/**
	 * @param {array} arrSoftwarePackages - The array of software packages from the response to the
	 *  Tanium REST API call to get all software packages.
	 * @returns {number[]} - An array of all software package IDs contained within the array of
	 *  software packages
	 * @private
	 */
	_getAllSpkgIDsFromResponse : function (arrSoftwarePackages) {
		var i, spkgID;
		var arrSpkgIDs = [];

		for (i = 0; i < arrSoftwarePackages.length; i++) {
			if (arrSoftwarePackages[i].hasOwnProperty('id')) {
				spkgID = arrSoftwarePackages[i].id;
				arrSpkgIDs.push(spkgID);
			}
		}

		return arrSpkgIDs;
	},

	/**
	 * Update any Deploy Software Packages in the array that were found in the
	 *  x_taniu_tan_core_deploy_spkg table, and return the remaining packages (those that weren't
	 *  already found in the table).
	 * @param arrSoftwarePackages
	 * @returns {[]} The original array of Tanium Deploy Package objects, BUT with all existing
	 *  packages REMOVED (so only those that weren't found in the table and potentially updated
	 *  will be included in the returned array).
	 * @private
	 */
	_updateFoundSoftwarePackages : function (arrSoftwarePackages) {
		var snFieldName, snFieldValue, objectPropName, objectPropValue,
			snPackageID, softwarePackageObject, spkgIndexInArray;
		var grSoftwarePackage = new GlideRecord('x_taniu_tan_core_deploy_spkg');

		grSoftwarePackage.query();

		/*
		 Iterate through all existing software package records in SN Deploy Spkg table.
		 For each spkg, find if there's an element of the array with that package ID.
			If there is, make sure the existing spkg in SN matches the data retrieved from Tanium.
			If not, create one.
		 For each spkg that's processed, remove it from the array so at the end, only spkgs which
		  weren't already in ServiceNow will be left in the array.
		 Pass the array of remaining objects to the _createMissingSoftwarePackages() method of
		  this SI.

		 upcoming_feature: This will later be broken up into functions.
		 */
		while (grSoftwarePackage.next()) {
			snPackageID = grSoftwarePackage.getValue('package_id');
			spkgIndexInArray = this._findPackageIndexFromArrayByID(
				arrSoftwarePackages,
				snPackageID
			);

			//If spkg is not in the array, carry on to the next one. This spkg does not exist in
			// SN, and will be created later.
			if (spkgIndexInArray < 0) {
				continue;
			}

			softwarePackageObject = new this._SoftwarePackage(
				arrSoftwarePackages[spkgIndexInArray]
			);

			for (snFieldName in softwarePackageObject.field_map) {
				//Prevent iteration into non-own properties.
				if (!softwarePackageObject.field_map.hasOwnProperty(snFieldName)) {
					continue;
				}

				objectPropName = softwarePackageObject.field_map[snFieldName];
				objectPropValue = softwarePackageObject[objectPropName];
				snFieldValue = grSoftwarePackage.getValue(snFieldName);

				if (typeof objectPropValue === 'undefined' || objectPropValue === null) {
					objectPropValue = '';
				}
				if (typeof snFieldValue === 'undefined' || snFieldValue === null) {
					snFieldValue = '';
				}
				if (snFieldName == 'description') {
					if (objectPropValue) {
						objectPropValue = objectPropValue.substring(0, 4990);
					}

					if (snFieldValue) {
						snFieldValue = snFieldValue.substring(0, 4990);
					}
				}

				if (objectPropValue != snFieldValue) {
					gs.debug(
						'SN field ' + snFieldName + ' value (' + snFieldValue + ') is not the ' +
						'same as value from object (' + objectPropValue + '). \n' +
						'SN field value type: ' + typeof snFieldValue + '. \n' +
						'Object prop value type: ' + typeof objectPropValue + '. \n' +
						'Spkg record ID: ' + grSoftwarePackage.getValue('sys_id') + '\n' +
						'Updating SN field value.'
					);

					grSoftwarePackage.setValue(snFieldName, objectPropValue);
				}
			}

			//Technically only updates if some field has changed as a result of the code above.
			grSoftwarePackage.update();

			//Remove software package from array since it has now been processed.
			arrSoftwarePackages.splice(spkgIndexInArray, 1);
		}

		//Returns array of remaining spkgs that weren't already found/updated.
		return arrSoftwarePackages;
	},

	_findPackageIndexFromArrayByID : function (arrSoftwarePackages, spkgID) {
		var i;

		for (i = 0; i < arrSoftwarePackages.length; i++) {
			if (arrSoftwarePackages[i].id == spkgID) {
				return i;
			}
		}

		return -1;
	},

	_validateResponseDataAssetItems : function (httpStatus, responseBody) {
		/*** BEGIN ERROR CHECKING DANCE ***/
		if (httpStatus.indexOf('20') != 0) {
			gs.error(
				'TaniumDeployUtil SI got invalid status when requesting ' +
				'details from Tanium Gateway API. Status: ' + httpStatus +
				'.\nResponse body:\n' + JSON.stringify(responseBody, null, 2)
			);
			return false; //Halt if non-success status.
		}

		if (
			!responseBody.hasOwnProperty('data') ||
			!responseBody.data.hasOwnProperty('assets') ||
			!responseBody.data.assets.hasOwnProperty('items') ||
			responseBody.data.assets.items.length < 1
		) {
			gs.error(
				'TaniumDeployUtil SI _validateResponseDataAssetItems method received invalid ' +
				'response body: \n' +
				JSON.stringify(responseBody, null, 2) + '\nHalting execution.'
			);
			return false; //Halt if error
		}

		/***ERROR CHECKING DANCE IS NOW OVER, RETURN TO YOUR LIVES ***/

		return true;
	},

	_createMissingSoftwarePackages : function (arrSoftwarePackages) {
		var i, snFieldName, objectPropName, objectPropValue, softwarePackageObject;
		var createdCount = 0;
		var grSoftwarePackage = new GlideRecord('x_taniu_tan_core_deploy_spkg');

		for (i = 0; i < arrSoftwarePackages.length; i++) {
			grSoftwarePackage.initialize();
			softwarePackageObject = new this._SoftwarePackage(
				arrSoftwarePackages[i]
			);

			for (snFieldName in softwarePackageObject.field_map) {
				//Prevent iteration into non-own properties.
				if (!softwarePackageObject.field_map.hasOwnProperty(snFieldName)) {
					continue;
				}

				objectPropName = softwarePackageObject.field_map[snFieldName];
				objectPropValue = softwarePackageObject[objectPropName];

				if (snFieldName == 'description') {
					objectPropValue = objectPropValue.substring(0, 2000);
				}
				if (typeof objectPropValue == 'undefined') {
					objectPropValue = '';
				}

				grSoftwarePackage.setValue(snFieldName, objectPropValue);
			}

			grSoftwarePackage.insert();
			createdCount++;
		}

		return createdCount;
	},

	_initDeployConfigIfEmpty: function() {
		if (typeof this._config === 'undefined') {
			this._config = {
				'description' : 'Deployment from ServiceNow',
					'spkg_id' : 0,
					'endpoints' : [],
					'operation' : 'INSTALL_OR_UPDATE',
					'start' : {},
				'end' : {},
				'last_deployment_id' : 0
			};
		}
	},

	/* *** ES5 FACTORY CLASSES BELOW *** */

	_SoftwarePackage : function (spkgObject) {
		//Declaring as variables first, so I can later add in some validation before setting the
		// local properties.

		var installedOn = 0,
			eligibleOn = 0,
			updateEligibleOn = 0,
			notApplicableOn = 0,
			x86Compatible = false,
			x64Compatible = false,
			arm64Compatible = false,
			packageID = spkgObject.id,
			packageName = spkgObject.productName,
			vendor = spkgObject.productVendor,
			productVersion = spkgObject.productVersion,
			platform = spkgObject.platform,
			currentEditID = spkgObject.currentSoftwarePackageEditId,
			description = spkgObject.description,
			distributed = spkgObject.hasBeenDistributed;

		if (
			spkgObject.hasOwnProperty('applicabilityCounts') &&
			!gs.nil(spkgObject.applicabilityCounts)
		) {
			installedOn = (
				spkgObject.applicabilityCounts.hasOwnProperty('installedCount')
			) ? spkgObject.applicabilityCounts.installedCount : 0;
			eligibleOn = (
				spkgObject.applicabilityCounts.hasOwnProperty('installEligibleCount')
			) ? spkgObject.applicabilityCounts.installEligibleCount : 0;
			updateEligibleOn = (
				spkgObject.applicabilityCounts.hasOwnProperty('updateEligibleCount')
			) ? spkgObject.applicabilityCounts.updateEligibleCount : 0;
			notApplicableOn = (
				spkgObject.applicabilityCounts.hasOwnProperty('notApplicableCount')
			) ? spkgObject.applicabilityCounts.notApplicableCount : 0;
		}

		if (
			spkgObject.hasOwnProperty('systemRequirements') &&
			!gs.nil(spkgObject.systemRequirements)
		) {
			x86Compatible = isCompatibleArchitecture(spkgObject, 'x86');
			x64Compatible = isCompatibleArchitecture(spkgObject, 'x64');
			arm64Compatible = isCompatibleArchitecture(spkgObject, 'arm64');
		}

		//upcoming_feature: Add in a bunch more validation n' such.

		this.package_id = packageID;
		this.package_name = packageName;
		this.package_vendor = vendor;
		this.product_version = productVersion;
		this.platform = platform;
		this.current_edit_id = currentEditID;
		this.description = description;
		this.installed_on_count = installedOn;
		this.eligible_on_count = eligibleOn;
		this.update_eligible_on_count = updateEligibleOn;
		this.not_applicable_on_count = notApplicableOn;
		this.x86_compatible = !!x86Compatible;
		this.x64_compatible = !!x64Compatible;
		this.arm64_compatible = !!arm64Compatible;
		this.distributed = !!distributed;

		//Key: SN field name.
		//Value: Property name containing that field's value
		this.field_map = {
			package_id : 'package_id',
			x86_compatible : 'x86_compatible',
			x64_compatible : 'x64_compatible',
			arm64_compatible : 'arm64_compatible',
			current_edit_id : 'current_edit_id',
			description : 'description',
			name : 'package_name',
			platform : 'platform',
			vendor : 'package_vendor',
			version : 'product_version',
			distributed : 'distributed',
			update_eligible_on : 'update_eligible_on_count',
			not_applicable_on : 'not_applicable_on_count',
			installed_on : 'installed_on_count',
			eligible_on : 'eligible_on_count'
		};

		function isCompatibleArchitecture(spkgObject, strArchitecture) {
			var systemRequirementsObj, requiredArchNodeName;
			var validArchitectures = ['x86', 'x64', 'arm64'];

			if (
				validArchitectures.indexOf(strArchitecture) < 0 ||
				!spkgObject.hasOwnProperty('systemRequirements')
			) {
				//Unsupported architecture passed in or spkgObject does not have requirements node
				return false;
			}

			if (strArchitecture.toLowerCase() === 'x86') {
				requiredArchNodeName = 'requires32BitSystem';
			} else if (strArchitecture.toLowerCase() === 'x64') {
				requiredArchNodeName = 'requires64BitSystem';
			}

			systemRequirementsObj = spkgObject.systemRequirements;

			/*
				There are two different ways to tell us a package is 32/64-bit compatible, and
				 one way to tell if it's arm64 compatible:

				If 32-bit:
					1. You may find the value "x86" in the array at
						spkgObj.systemRequirements.allowedArchitectures.
					2. You may find a node at spkgObj.systemRequirements.requires32BitSystem,
						which will be set to the boolean true.
				If 64-bit:
					1. You may find the value "x64" in the array at
						spkgObj.systemRequirements.allowedArchitectures.
					2. You may find a node at spkgObj.systemRequirements.requires64BitSystem,
						which will be set to the boolean true.
				If arm64:
					1. You may find the value "arm64" in the array at
						spkgObj.systemRequirements.allowedArchitectures.

				The below code checks for both possibilities, for one of the three possible architectures we support, depending on which was passed in as the value of the strArchitecture argument.
			 */

			//Scenario 1: The "new" pattern for determining architecture compatibility using the
			// allowedArchitectures array.
			//(Works on newer Deploy packages)
			if (
				//allowedArchitectures node exists
				systemRequirementsObj.hasOwnProperty('allowedArchitectures') &&
				//allowedArchitectures arr contains x86/x64/arm64 (value in strArchitecture arg)
				systemRequirementsObj.allowedArchitectures.indexOf(strArchitecture.toLowerCase()) > 0
			) {
				return true;
			}

			//Scenario 2: The "old" pattern for determining architecture compatibility
			//(Works on older Deploy packages)
			if (
				//requiredArchNodeName variable is set (only happens for x86/x64 architectures)
				requiredArchNodeName &&
				//"requires32BitSystem"/"requires64BitSystem" node exists (based on strArchitecture)
				systemRequirementsObj.hasOwnProperty(requiredArchNodeName) &&
				//"requires32BitSystem" or "requires64BitSystem" node is set to true
				systemRequirementsObj[requiredArchNodeName] === true
			) {
				return true;
			}

			/*
				If none of the checks above returned true then the architecture specified in
				 the strArchitecture arg is not supported by this package, so return false.
			 */
			return false;
		}
	},

	deploy_package_table_name : 'x_taniu_tan_core_deploy_spkg',

	type : 'TaniumDeployUtil'
});
